    print("\n‚îÄ‚îÄ LOCAL TASTES ‚Äî no <p> tags inside section ‚îÄ‚îÄ")
    # H ‚Äî No <p> tags inside the Local Tastes section (all content is in <div>s)
    _lt_p_tags: list[str] = []
    if _lt_hdr:
        for _lt_pm in re.finditer(r'<p\b[^>]*>(.*?)</p>', _lt_body, re.DOTALL | re.IGNORECASE):
            _lt_p_text = RE_STRIP_TAGS.sub('', _lt_pm.group(1)).strip()[:80]
