        _ride_sub_m = _ride_sub_re.search(_ga_html)
        if _ride_sub_m:
            _after_ride = _ga_html[_ride_sub_m.end():]
            _tb_m = re.search(r'<div\b[^>]*class\s*=\s*"[^"]*\btransit-box\b[^"]*"[^>]*>', _after_ride, re.IGNORECASE)
            if _tb_m:
                _tb_inner, _ = _walk_balanced_div(_after_ride, _tb_m.end())
                for _rdm in re.finditer(r'<div\b[^>]*>(.*?)</div>', _tb_inner, re.DOTALL):
                    _row = RE_STRIP_TAGS.sub( '', _rdm.group(1)).strip()
