    # ‚îÄ‚îÄ‚îÄ RESTAURANTS / DOWNTOWN ‚Äî üö∂ ROW REQUIRED IN EVERY SHOWS-BOX ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    print("\n‚îÄ‚îÄ RESTAURANTS ‚Äî üö∂ ROW IN SHOWS-BOX ‚îÄ‚îÄ")
    _rest_walk_missing: list[str] = []
    for _sec_id in ('cappuccino', 'restaurants'):  # downtown is district-scoped ‚Äî no üö∂ per Doc
        _rs_m = re.search(
            rf'<div\b[^>]*class\s*=\s*"[^"]*\bextras-section\b[^"]*"[^>]*\bid\s*=\s*"{_sec_id}"[^>]*>',
            html, re.IGNORECASE,
        )
        if not _rs_m:
            continue
        _rs_inner, _ = _walk_balanced_div(html, _rs_m.end())
        for _sb_m in re.finditer(
            r'<div\b[^>]*class\s*=\s*"[^"]*\bshows-box\b[^"]*"[^>]*>',
            _rs_inner, re.IGNORECASE,
        ):
            _sb_inner, _ = _walk_balanced_div(_rs_inner, _sb_m.end())
            # Find the preceding extras-sub to get the venue name
            _pre = _rs_inner[:_sb_m.start()]
            _esub_m = list(re.finditer(
                r'<div\b[^>]*class\s*=\s*"[^"]*\bextras-sub\b[^"]*"[^>]*>(.*?)</div>',
                _pre, re.DOTALL | re.IGNORECASE,
            ))
            _venue = RE_STRIP_TAGS.sub( '', _esub_m[-1].group(1)).strip()[:40] if _esub_m else '?'
            if 'üö∂' not in _sb_inner:
                _rest_walk_missing.append(f'"{_venue}" ({_sec_id}) shows-box missing üö∂ row')
