        'barcelona', 'madrid', 'san sebastian', 'seville', 'toledo',
        # Portugal  (Lagos here = Algarve, Portugal ‚Äî the European Lagos)
        # azores ‚Äî island archipelago, no rail service; see _ISLAND_CITIES 2026-06-15
        # madeira ‚Äî island, no rail service; see _ISLAND_CITIES 2026-06-15
        'cascais', 'lagos', 'lisbon', 'porto', 'sintra',
        # Germany
        'berlin', 'marktoberdorf', 'munich', 'stuttgart',
        # Austria
        'salzburg', 'vienna',
        # Switzerland
        'geneva', 'lucerne', 'zurich',
        # United Kingdom
        'cambridge', 'edinburgh', 'glasgow', 'london',
        # Ireland
        'dublin',
